560 int
561 epoll_helper (int *fds, int *levelfds, libcrun_error_t *err)
562 {
563   struct epoll_event ev;
564   cleanup_close int epollfd = -1;
565   int ret;
566 
567   int *it;
568   epollfd = epoll_create1 (0);
569   if (UNLIKELY (epollfd < 0))
570     return crun_make_error (err, errno, "epoll_create1");
571 
572   for (it = fds; *it >= 0; it++)
573     {
574       ev.events = EPOLLIN;
575       ev.data.fd = *it;
576       ret = epoll_ctl (epollfd, EPOLL_CTL_ADD, *it, &ev);
577       if (UNLIKELY (ret < 0))
578         return crun_make_error (err, errno, "epoll_ctl add '%d'", *it);
579     }
580   for (it = levelfds; *it >= 0; it++)
581     {
582       ev.events = EPOLLIN | EPOLLET;
583       ev.data.fd = *it;
584       ret = epoll_ctl (epollfd, EPOLL_CTL_ADD, *it, &ev);
585       if (UNLIKELY (ret < 0))
586         return crun_make_error (err, errno, "epoll_ctl add '%d'", *it);
587     }
588 
589   ret = epollfd;
590   epollfd = -1;
