594 int
595 copy_from_fd_to_fd (int src, int dst, int consume, libcrun_error_t *err)
596 {
597   int ret;
598   ssize_t nread;
599   do
600     {
601       cleanup_free char *buffer = NULL;
602       ssize_t remaining;
603 
604 #ifdef HAVE_COPY_FILE_RANGE
605       nread = copy_file_range (src, NULL, dst, NULL, 0, 0);
606       if (nread < 0 && errno == EINVAL)
607         goto fallback;
608       if (consume && nread < 0 && errno == EAGAIN)
609         return 0;
610       if (nread < 0 && errno == EIO)
611         return 0;
612       if (UNLIKELY (nread < 0))
613         return crun_make_error (err, errno, "copy_file_range");
614 
615     fallback:
616 #endif
617 # define BUFFER_SIZE 4096
618 
619       buffer = xmalloc (BUFFER_SIZE);
620       nread = TEMP_FAILURE_RETRY (read (src, buffer, BUFFER_SIZE));
621       if (consume && nread < 0 && errno == EAGAIN)
622         return 0;
623       if (nread < 0 && errno == EIO)
624         return 0;
625       if (UNLIKELY (nread < 0))
626         return crun_make_error (err, errno, "read");
627 
628       remaining = nread;
629       while (remaining)
630         {
631           ret = TEMP_FAILURE_RETRY (write (dst, buffer, nread));
632           if (UNLIKELY (ret < 0))
633             return crun_make_error (err, errno, "write");
634           remaining -= ret;
635         }
636     }
637   while (consume && nread);
638 
639   return 0;
640 
641 }
