868 int
869 close_fds_ge_than (int n, libcrun_error_t *err)
870 {
871   int fd;
872   cleanup_dir DIR *dir = NULL;
873   int ret;
874   struct dirent *next;
875 
876   dir = opendir ("/proc/self/fd");
877   if (UNLIKELY (dir == NULL))
878     return crun_make_error (err, errno, "cannot fdopendir /proc/self/fd");
879 
880   fd = dirfd (dir);
881   for (next = readdir (dir); next; next = readdir (dir))
882     {
883       int val;
884       const char *name = next->d_name;
885       if (name[0] == '.')
886         continue;
887 
888       val = strtoll (name, NULL, 10);
889       if (val < n || val == fd)
890         continue;
891 
892       ret = fcntl (val, F_SETFD, FD_CLOEXEC);
893       if (UNLIKELY (ret < 0))
894         return crun_make_error (err, errno, "cannot set CLOEXEC fd for '/proc/self/fd/%s'", name);
895     }
896   return 0;
897 }
